INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '1. Emplea los conocimientos y habilidades tecnológicos necesarios para realizar documentos digitales.', ARRAY['1.1. Describe la importancia que tiene la tecnología, los cuidados del equipo y la relación con la salud.', '1.2. Digita al tacto en forma ergonómica, con exactitud y la técnica correcta.', '1.3. Demuestra destrezas, habilidades y técnicas básicas en la elaboración de documentos de uso cotidiano.', '1.4. Redacta documentos en procesadores de texto.']),
('Primero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '2. Utiliza recursos digitales para la realización de materiales académicos de manera responsable, empleando protocolos de seguridad informática.', ARRAY['2.1. Selecciona diferentes herramientas tecnológicas en internet, apropiadas para comunicar y recibir información.', '2.2. Desarrolla una cultura de respeto ante las diferentes opiniones al elaborar trabajos colaborativos.', '2.3. Establece diferencias entre la información con base bibliográfica y la información sin respaldo académico.', '2.4. Traslada electrónicamente documentos de texto a destinatarios.']),
('Primero Básico', 'Tecnologías del Aprendizaje y la Comunicación', '3. Emplea tecnologías colaborativas e interactivas en trabajos escolares con compañeros, dentro y fuera del espacio de aprendizaje.', ARRAY['3.1. Identifica sitios confiables para su trabajo escolar y aprendizajes oportunos.', '3.2. Utiliza herramientas colaborativas para desarrollar diversas actividades.', '3.3. Presenta documentos de acuerdo con las normas generales de presentación.']);
